import React from "react"
import { Link, graphql } from "gatsby"
import { rhythm } from "../utils/typography"
import SEO from "../components/seo"
import Layout from "../components/layout"
import Header from "../components/header"

const AllPosts = ({ data, location }) => {
  const posts = data.allMarkdownRemark.edges

  return (
    <html lang="en" style={{ backgroundColor: '#fff' }}>
    <Layout location={location} >
      <Header location={location}/>
      <p style={{ marginTop: '1.5rem' }}>Calling the following pieces of writing blog posts is generous. I don't promise proper grammar or spelling. Godspeed reader.</p>
        <SEO title="All posts" />
        {posts.map(({ node }) => {
        const title = node.frontmatter.title || node.fields.slug
        return (
          <article key={node.fields.slug}>
            <header>
              <h3
                style={{
                  marginBottom: rhythm(1 / 4),
                }}
              >
                <Link style={{ boxShadow: `none` }} to={node.fields.slug}>
                  {title}
                </Link>
              </h3>
              <p>{node.frontmatter.date}</p>
            </header>
            <section>
              <p
                dangerouslySetInnerHTML={{
                  __html: node.frontmatter.description || node.excerpt,
                }}
              />
            </section>
          </article>
        )
      })}
      <footer>
        <p style={{ fontSize: `12px` }}>
          © {new Date().getFullYear()}, Built with <a href="https://www.gatsbyjs.org">Gatsby</a> by Marissa Phul
        </p>
      </footer>
    </Layout>
  </html>
  )
}

export default AllPosts

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      edges {
        node {
          excerpt
          fields {
            slug
          }
          frontmatter {
            date(formatString: "MMMM DD, YYYY")
            title
            description
          }
        }
      }
    }
  }
`
